import { useState, useEffect } from "react";
import { recipeAPI, userAPI } from "../../services/api";
import RecipeCard from "../../components/RecipeCard";

const NAV = [
  { icon: "🏠", label: "Feed", id: "feed", active: true },
  { icon: "❤️", label: "Saved", id: "saved" },
  { icon: "👨‍🍳", label: "Following", id: "following" },
  { icon: "👤", label: "Profile", id: "profile" },
];

export default function UserDashboardPage({ setPage, setSelectedRecipe, user }) {
  const [activeNav, setActiveNav] = useState("feed");
  const [recipes, setRecipes] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState("");

  useEffect(() => {
    if (activeNav === "feed") {
      fetchFeed();
    } else if (activeNav === "saved") {
      fetchSavedRecipes();
    }
  }, [activeNav]);

  const fetchFeed = async () => {
    try {
      setLoading(true);
      const response = await recipeAPI.getAll({ limit: 20 });
      if (response.data.success) {
        setRecipes(response.data.data);
      }
    } catch (err) {
      console.error("Error fetching feed:", err);
      setError("Failed to load recipes");
    } finally {
      setLoading(false);
    }
  };

  const fetchSavedRecipes = async () => {
    try {
      setLoading(true);
      const response = await recipeAPI.getSavedRecipes();
      if (response.data.success) {
        setRecipes(response.data.data);
      }
    } catch (err) {
      console.error("Error fetching saved recipes:", err);
      setError("Failed to load saved recipes");
    } finally {
      setLoading(false);
    }
  };

  const handleLike = async (recipeId) => {
    try {
      await recipeAPI.like(recipeId);
      // Update local state
      setRecipes(prev => prev.map(recipe => 
        recipe._id === recipeId 
          ? { ...recipe, likes: recipe.likes?.includes(user._id) 
              ? recipe.likes.filter(id => id !== user._id)
              : [...(recipe.likes || []), user._id] }
          : recipe
      ));
    } catch (err) {
      console.error("Error liking recipe:", err);
    }
  };

  const handleSave = async (recipeId) => {
    try {
      await recipeAPI.save(recipeId);
      // Update local state
      setRecipes(prev => prev.map(recipe => 
        recipe._id === recipeId 
          ? { ...recipe, savedBy: recipe.savedBy?.includes(user._id)
              ? recipe.savedBy.filter(id => id !== user._id)
              : [...(recipe.savedBy || []), user._id] }
          : recipe
      ));
    } catch (err) {
      console.error("Error saving recipe:", err);
    }
  };

  const handleFollow = async (chefId) => {
    try {
      await userAPI.follow(chefId);
      // Update local state if needed
    } catch (err) {
      console.error("Error following user:", err);
    }
  };

  const renderFeed = () => (
    <div style={{ display: "flex", flexDirection: "column", gap: "24px" }}>
      {recipes.map(recipe => (
        <div key={recipe._id} style={{ 
          background: "var(--white)", 
          borderRadius: "var(--radius-lg)", 
          overflow: "hidden",
          boxShadow: "var(--shadow-sm)",
          border: "1px solid var(--border-light)"
        }}>
          {/* Recipe Header */}
          <div style={{ padding: "16px 20px", borderBottom: "1px solid var(--border-light)" }}>
            <div style={{ display: "flex", alignItems: "center", gap: "12px" }}>
              <img 
                src={recipe.chef?.avatar || "https://via.placeholder.com/40"} 
                alt={recipe.chef?.name} 
                style={{ width: "40px", height: "40px", borderRadius: "50%", objectFit: "cover" }}
              />
              <div>
                <div style={{ fontWeight: "600", color: "var(--text-main)" }}>{recipe.chef?.name || "Chef"}</div>
                <div style={{ fontSize: "12px", color: "var(--text-muted)" }}>
                  {new Date(recipe.createdAt).toLocaleDateString()}
                </div>
              </div>
              <button 
                style={{ marginLeft: "auto", padding: "6px 12px", border: "1px solid var(--border-light)", borderRadius: "20px", background: "var(--bg)", fontSize: "12px" }}
                onClick={() => handleFollow(recipe.chef._id)}
              >
                Follow
              </button>
            </div>
          </div>

          {/* Recipe Image */}
          <div style={{ position: "relative" }}>
            <img 
              src={recipe.image} 
              alt={recipe.title} 
              style={{ width: "100%", height: "300px", objectFit: "cover", cursor: "pointer" }}
              onClick={() => {
                setSelectedRecipe(recipe);
                setPage("recipe-detail");
              }}
            />
          </div>

          {/* Recipe Content */}
          <div style={{ padding: "16px 20px" }}>
            <h3 style={{ fontSize: "18px", fontWeight: "700", marginBottom: "8px", cursor: "pointer" }}
                onClick={() => {
                  setSelectedRecipe(recipe);
                  setPage("recipe-detail");
                }}>
              {recipe.title}
            </h3>
            <p style={{ color: "var(--text-muted)", fontSize: "14px", marginBottom: "16px" }}>
              {recipe.description}
            </p>

            {/* Tags */}
            <div style={{ display: "flex", gap: "8px", marginBottom: "16px" }}>
              <span style={{ 
                background: "var(--primary)", 
                color: "white", 
                padding: "4px 8px", 
                borderRadius: "12px", 
                fontSize: "12px",
                fontWeight: "500"
              }}>
                {recipe.tag}
              </span>
              <span style={{ 
                background: "var(--bg)", 
                color: "var(--text-main)", 
                padding: "4px 8px", 
                borderRadius: "12px", 
                fontSize: "12px",
                fontWeight: "500"
              }}>
                {recipe.difficulty}
              </span>
            </div>

            {/* Actions */}
            <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between" }}>
              <div style={{ display: "flex", alignItems: "center", gap: "16px" }}>
                <button 
                  style={{ 
                    display: "flex", 
                    alignItems: "center", 
                    gap: "6px", 
                    background: "none", 
                    border: "none", 
                    color: recipe.likes?.includes(user._id) ? "#ef4444" : "var(--text-muted)",
                    fontSize: "14px",
                    cursor: "pointer"
                  }}
                  onClick={() => handleLike(recipe._id)}
                >
                  ❤️ {recipe.likes?.length || 0}
                </button>
                <button 
                  style={{ 
                    display: "flex", 
                    alignItems: "center", 
                    gap: "6px", 
                    background: "none", 
                    border: "none", 
                    color: recipe.savedBy?.includes(user._id) ? "#eab308" : "var(--text-muted)",
                    fontSize: "14px",
                    cursor: "pointer"
                  }}
                  onClick={() => handleSave(recipe._id)}
                >
                  🔖 {recipe.savedBy?.length || 0}
                </button>
              </div>
              <button 
                style={{ 
                  background: "var(--primary)", 
                  color: "white", 
                  border: "none", 
                  padding: "8px 16px", 
                  borderRadius: "20px", 
                  fontSize: "14px",
                  cursor: "pointer"
                }}
                onClick={() => {
                  setSelectedRecipe(recipe);
                  setPage("recipe-detail");
                }}
              >
                View Recipe
              </button>
            </div>
          </div>
        </div>
      ))}
    </div>
  );

  return (
    <div className="sidebar-layout">
      {/* SIDEBAR */}
      <aside className="sidebar">
        <div style={{ padding: "0 8px 32px" }}>
          <div style={{ display: "flex", alignItems: "center", gap: "10px", marginBottom: "32px" }}>
            <div style={{ width: "32px", height: "32px", background: "var(--primary)", borderRadius: "8px", display: "flex", alignItems: "center", justifyContent: "center", fontSize: "16px", color: "#fff" }}>🍽</div>
            <span className="serif" style={{ fontSize: "18px", fontWeight: "700", color: "var(--navy)" }}>RecipeNest</span>
          </div>

          <div style={{ display: "flex", flexDirection: "column", gap: "4px" }}>
            {NAV.map(item => (
              <button 
                key={item.id} 
                className={`sidebar-item ${activeNav === item.id ? "active" : ""}`} 
                onClick={() => setActiveNav(item.id)}
              >
                <span style={{ fontSize: "18px" }}>{item.icon}</span>
                {item.label}
              </button>
            ))}
          </div>
        </div>

        <div style={{ marginTop: "auto", padding: "20px 8px 0", borderTop: "1px solid var(--border-light)" }}>
          <div style={{ display: "flex", alignItems: "center", gap: "12px", padding: "12px", background: "var(--bg)", borderRadius: "var(--radius-md)", marginBottom: "16px", border: "1px solid var(--border-light)" }}>
            <div className="sidebar-avatar" style={{ width: "40px", height: "40px", fontSize: "14px", fontWeight: "700", background: "var(--primary)", color: "#fff", display: "flex", alignItems: "center", justifyContent: "center", borderRadius: "10px" }}>{user?.name?.[0] || 'U'}</div>
            <div>
              <div style={{ fontSize: "13px", fontWeight: "700", color: "var(--text-main)" }}>{user?.name || "User"}</div>
              <div style={{ fontSize: "11px", color: "var(--text-muted)" }}>Home Cook</div>
            </div>
          </div>

          <button className="logout-btn" onClick={() => setPage("home")}>
            <span>🚪</span> Logout
          </button>
        </div>
      </aside>

      {/* CONTENT */}
      <main className="page-content">
        <div className="page-header" style={{ marginBottom: "40px" }}>
          <div>
            <h1 className="page-title">
              {activeNav === "feed" ? "Recipe Feed" : 
               activeNav === "saved" ? "Saved Recipes" :
               activeNav === "following" ? "Following" : "Profile"}
            </h1>
            <p className="page-sub">
              {activeNav === "feed" ? "Discover amazing recipes from chefs around the world" :
               activeNav === "saved" ? "Your saved recipes for later" :
               activeNav === "following" ? "Recipes from chefs you follow" : "Manage your profile"}
            </p>
          </div>
        </div>

        {loading ? (
          <div style={{ textAlign: "center", padding: "40px" }}>
            <div style={{ 
              width: "40px", 
              height: "40px", 
              border: "4px solid var(--border-light)", 
              borderTop: "4px solid var(--primary)", 
              borderRadius: "50%", 
              animation: "spin 1s linear infinite",
              margin: "0 auto 16px"
            }} />
            <p>Loading recipes...</p>
          </div>
        ) : error ? (
          <div style={{ textAlign: "center", padding: "40px", color: "#ef4444" }}>
            {error}
          </div>
        ) : (
          renderFeed()
        )}
      </main>
    </div>
  );
}
